        '',
        `ANALYSIS FILE DIGEST:\n${toolOutputs.analysisDigest}`,
        '',
        `BOOK EXCERPTS:\n${toolOutputs.bookDigest}`,
        '',
        `STRATEGY RULES:\n${toolOutputs.strategyRules}`,
        '',
        `REPO CODE CONTEXT:\n${toolOutputs.codeDigest}`,
