async function ensureLangChainRuntime() {
    if (state.langChainRuntime) return state.langChainRuntime;
    if (!state.langChainRuntimePromise) {
        state.langChainRuntimePromise = import(CONFIG.zai.imports.openai).then(openAiModule => {
            const runtime = {
                ChatOpenAI: openAiModule.ChatOpenAI
            };
            state.langChainRuntime = runtime;
            return runtime;
        });
    }
    return state.langChainRuntimePromise;
}

function buildAgentSystemPrompt() {
    return [
        'You are Astro Trading Research, a frontend LangChain market-and-astrology analyst for commodity and crypto timing decisions.',
        'Reason from the supplied local tool outputs before giving trading guidance.',
        'Use the correct instrument names: Tata Gold ETF, Groww Silver ETF, Hindustan Copper, Bitcoin.',
        'Treat all planetary dates as timing windows, not exact timestamps.',
        'Only mention one-day-before or two-days-before entries when price action is already aligning.',
        'If the user asks for a chart, refer to the attached chart data explicitly.',
        'If the user asks for a backtest, clearly label it as lightweight local backtesting.',
        'Avoid mentioning backend services, Netlify, Codex, or hidden infrastructure. This is a frontend agent.'
    ].join('\n');
}

function collectFrontendToolOutputs(requestContext) {
    const chart = requestContext.chart || (detectChartIntent(requestContext.message) ? buildChartPayload(requestContext.scope, requestContext.message) : null);
    const bookModeContext = BOOKS[requestContext.book]?.context || BOOKS.general.context;
    const commodityGuidance = requestContext.scope && requestContext.scope !== 'overview'
        ? COMMODITY_CONTEXT[requestContext.scope]?.context || 'Overview mode.'
        : Object.values(COMMODITY_CONTEXT).map(item => `${item.name}\n${item.context}`).join('\n\n').slice(0, 4500);
    const outputs = {
        bookModeContext,
        commodityGuidance,
        marketSnapshot: buildScopedMarketDigest(requestContext.scope),
        analysisDigest: buildAnalysisDigest(requestContext.analysisContext, requestContext.scope),
        bookDigest: buildBooksDigest(requestContext.bookContext, requestContext.message, requestContext.scope, requestContext.book),
        strategyRules: buildStrategyDigest(requestContext.strategyContext),
        codeDigest: buildCodeDigest(requestContext.codeContext, requestContext.message),
        chart,
        backtest: requestContext.backtestRequested ? runLightweightBacktest(requestContext.scope) : ''
    };
    requestContext.chart = chart;
    requestContext.toolOutputs = outputs;
    return outputs;
}

async function ensureFrontendAgent() {
    if (!state.apiKey) {
        throw new Error('Add a ZAI API key to use the frontend LangChain agent.');
    }
    if (state.agentBundle) return state.agentBundle;
    if (!state.agentBundlePromise) {
        state.agentBundlePromise = (async () => {
            const runtime = await ensureLangChainRuntime();
            const { ChatOpenAI } = runtime;
            const sharedConfig = {
                apiKey: state.apiKey,
                temperature: 0.2,
                maxTokens: 1100,
                configuration: {
                    baseURL: CONFIG.zai.apiUrl,
                    dangerouslyAllowBrowser: true
                }
            };
            const primaryModel = new ChatOpenAI({
                model: CONFIG.zai.primaryModel,
                ...sharedConfig
            });
            const fallbackModel = new ChatOpenAI({
                model: CONFIG.zai.fallbackModel,
                ...sharedConfig
            });

            state.agentBundle = { primaryModel, fallbackModel };
            return state.agentBundle;
        })();
    }
    return state.agentBundlePromise;
}

async function sendChatViaAgent({ msg, history }) {
    const currentScope = getChatScope();
    const scope = currentScope === 'overview' ? inferCommodityFromMessage(msg) : currentScope;
    const book = document.getElementById('book-select')?.value || 'general';
    if (!state.apiKey) {
        throw new Error('Add your ZAI API key above to use the frontend agent.');
    }

    setAgentStatus('Loading LangChain runtime');
    const [analysisContext, bookContext, strategyContext, codeContext] = await Promise.all([
        loadAnalysisFileContext(),
        loadBookTextContext(),
        loadStrategyContext(),
        loadCodeContext()
    ]);

    state.agentRequestContext = {
        scope,
        book,
        message: msg,
        analysisContext,
        bookContext,
        strategyContext,
        codeContext,
        chart: detectChartIntent(msg) ? buildChartPayload(scope, msg) : null,
        backtest: '',
        backtestRequested: detectBacktestIntent(msg)
    };

    try {
        setAgentStatus('Preparing frontend tools');
        collectFrontendToolOutputs(state.agentRequestContext);
        const { primaryModel, fallbackModel } = await ensureFrontendAgent();
        const prompt = buildDirectPrompt({
            requestContext: state.agentRequestContext,
            history
        });
        const messages = [
            { role: 'system', content: buildAgentSystemPrompt() },
            { role: 'user', content: prompt }
        ];

        setAgentStatus(`Calling ${CONFIG.zai.primaryModel}`);
        try {
            const primaryResponse = await primaryModel.invoke(messages);
            const primaryContent = normalizeModelContent(primaryResponse?.content);
            if (primaryContent) {
                return {
                    content: primaryContent,
                    model: primaryResponse?.response_metadata?.model_name || CONFIG.zai.primaryModel,
                    chart: state.agentRequestContext.chart
                };
            }
        } catch (primaryError) {
            console.warn('Primary LangChain model call failed, using fallback model.', primaryError);
        }

        setAgentStatus(`Calling ${CONFIG.zai.fallbackModel}`);
        const fallbackResponse = await fallbackModel.invoke(messages);
        const fallbackContent = normalizeModelContent(fallbackResponse?.content);
        if (!fallbackContent) {
            throw new Error('The frontend model returned an empty response.');
        }
        return {
            content: fallbackContent,
            model: fallbackResponse?.response_metadata?.model_name || CONFIG.zai.fallbackModel,
            chart: state.agentRequestContext.chart
        };
    } finally {
        state.agentRequestContext = null;
    }
}

async function warmContextCaches() {
    await Promise.all([
        loadAnalysisFileContext(),
        loadBookTextContext(),
        loadStrategyContext(),
        loadCodeContext()
    ]);
    state.contextReady = true;
}

async function sendChat() {
    const input = document.getElementById('chat-input');
    const msg = input.value.trim();
    if (!msg || state.isSending) return;

    state.isSending = true;
    input.value = '';
    addMessageToUI('user', msg);
    const thread = getCurrentThread();
    const history = thread.messages;
    history.push({ role: 'user', content: msg });
    if (!thread.title || thread.title === 'New thread' || /^Thread \d+$/.test(thread.title)) {
        thread.title = msg.slice(0, 36) || thread.title;
    }
    saveChatHistory();

    // Create streaming message placeholder
    const streamingMsgId = 'stream-' + Date.now();
    addStreamingMessage(streamingMsgId);
    setAgentStatus(`Consulting ${CONFIG.zai.primaryModel}`);
    let ticker = null;

    try {
        const resultPromise = sendChatViaAgent({ msg, history });
        ticker = window.setInterval(() => {
            const el = document.getElementById(streamingMsgId);
            if (!el) return;
            const contentEl = el.querySelector('.msg-content');
            if (!contentEl) return;
            const statusText = document.querySelector('.chat-status')?.textContent || 'Working';
            contentEl.innerHTML = `<em>${escapeHtml(statusText)}...</em><span class="streaming-cursor">|</span>`;
        }, 150);
        const result = await resultPromise;
        window.clearInterval(ticker);
        ticker = null;
        if (result?.content) {
            if (result.chart) {
                removeStreamingMessage(streamingMsgId);
                addMessageToUI('assistant', result.content, { chart: result.chart });
            } else {
                finalizeStreamingMessage(streamingMsgId, result.content);
            }
            history.push({ role: 'assistant', content: result.content, chart: result.chart || null });
            saveChatHistory();
            renderThreadOptions();
            setAgentStatus(`${result.model} ready`);
            state.isSending = false;
            return;
        }

        throw new Error('Empty model response');
    } catch (agentError) {
        if (ticker) window.clearInterval(ticker);
        console.error('Agent error:', agentError);
        setAgentStatus('Agent unavailable');
        removeStreamingMessage(streamingMsgId);
        addMessageToUI('assistant', `⚠️ ${String(agentError?.message || 'Model request failed.')}`);
        state.isSending = false;
    }

    state.isSending = false;
}

function addStreamingMessage(id) {
    const container = document.getElementById('chat-messages');
    const div = document.createElement('div');
    div.className = 'msg streaming';
    div.id = id;
    div.innerHTML = '<span class="avatar ai">AI</span><div class="msg-content"><span class="streaming-cursor">|</span></div>';
    container.appendChild(div);
    container.scrollTop = container.scrollHeight;
}

function updateStreamingMessage(id, content) {
    const el = document.getElementById(id);
    if (el) {
        const contentEl = el.querySelector('.msg-content');
        if (contentEl) {
            contentEl.innerHTML = formatContent(content) + '<span class="streaming-cursor">|</span>';
        }
        el.scrollIntoView({ behavior: 'smooth', block: 'end' });
    }
}

function finalizeStreamingMessage(id, content) {
    const el = document.getElementById(id);
    if (el) {
        el.className = 'msg';
        const contentEl = el.querySelector('.msg-content');
        if (contentEl) {
            contentEl.innerHTML = formatContent(content);
        }
    }
}

function removeStreamingMessage(id) {
    const el = document.getElementById(id);
    if (el) el.remove();
}

function buildInlineChartConfig(chartPayload) {
    const labels = Array.isArray(chartPayload?.labels) ? chartPayload.labels : [];
    const datasets = Array.isArray(chartPayload?.datasets) ? chartPayload.datasets : [];
    return {
        type: chartPayload?.type || 'line',
        data: {
            labels,
            datasets: datasets.map((dataset, index) => ({
                label: dataset.label || `Series ${index + 1}`,
                data: Array.isArray(dataset.data) ? dataset.data : [],
                borderColor: dataset.borderColor || ['#fbbf24', '#c0c0c0', '#cd7f32', '#f7931a'][index % 4],
                backgroundColor: dataset.backgroundColor || 'rgba(251, 191, 36, 0.12)',
                fill: Boolean(dataset.fill),
                tension: 0.3,
                borderWidth: 2,
                pointRadius: 2
            }))
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            plugins: {
                legend: {
                    labels: {
                        color: '#d6d6d6',
                        font: { size: 11 }
                    }
                },
                title: chartPayload?.title
                    ? {
                        display: true,
                        text: chartPayload.title,
                        color: '#f3f4f6',
                        font: { size: 12, weight: '600' }
                    }
                    : undefined
            },
            scales: {
                x: {
                    ticks: { color: '#9ca3af' },
                    grid: { color: 'rgba(255,255,255,0.05)' }
                },
                y: {
                    ticks: { color: '#9ca3af' },
                    grid: { color: 'rgba(255,255,255,0.05)' }
                }
            }
        }
    };
}

function renderInlineChatChart(canvasId, chartPayload) {
    const canvas = document.getElementById(canvasId);
    if (!canvas || typeof Chart === 'undefined') return;
    state.chatCharts[canvasId]?.destroy?.();
    state.chatCharts[canvasId] = new Chart(canvas, buildInlineChartConfig(chartPayload));
}

function askAI(question) {
    document.getElementById('chat-input').value = question;
    sendChat();
}

function addMessageToUI(role, content, options = {}) {
    const container = document.getElementById('chat-messages');
    const div = document.createElement('div');
    div.className = `msg ${role === 'user' ? 'user' : ''}`;

    const avatarClass = role === 'user' ? 'avatar' : 'avatar ai';
    const avatarText = role === 'user' ? 'You' : 'AI';
    const chart = options.chart;
    const chartId = chart ? `chat-chart-${Date.now()}-${Math.random().toString(36).slice(2, 7)}` : '';
    const chartMarkup = chart
        ? `<div class="inline-chart-card"><div class="inline-chart-meta">${escapeHtml(chart.title || 'Chart')}</div><div class="inline-chart-wrap"><canvas id="${chartId}"></canvas></div></div>`
        : '';
    div.innerHTML = `<span class="${avatarClass}">${avatarText}</span><div class="msg-content">${formatContent(content)}${chartMarkup}</div>`;

    container.appendChild(div);
    container.scrollTop = container.scrollHeight;
    if (chart) {
        queueMicrotask(() => renderInlineChatChart(chartId, chart));
    }
}

function escapeHtml(text) {
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
}

function formatContent(text) {
    // Use marked.js for markdown rendering if available
    if (typeof marked !== 'undefined') {
        try {
            return marked.parse(text);
        } catch (e) {
            console.warn('Marked parse error:', e);
        }
    }

    return escapeHtml(text)
        .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
        .replace(/\*(.*?)\*/g, '<em>$1</em>')
        .replace(/`(.*?)`/g, '<code>$1</code>')
        .replace(/\n/g, '<br>');
}

// ========== COUNTDOWNS ==========
function updateCountdowns() {
    const now = new Date();
    const apr1 = new Date(now.getFullYear(), 3, 1);

    if (apr1 > now) {
        const days = Math.ceil((apr1 - now) / 86400000);
        const el = document.getElementById('copper-countdown');
        if (el) el.textContent = `${days} days until SUPER BULLISH period`;
    }
}

// ========== INIT ==========
document.addEventListener('DOMContentLoaded', () => {
    loadPriceHistory();
    loadChatHistory();
    initChatResize();
    initCharts();
    renderRecommendations();
    refreshAllData();
    updateCountdowns();
    updateChatContext();
    updateApiKeyUI();
    warmContextCaches()
        .then(() => setAgentStatus(state.apiKey ? 'Frontend context ready' : 'Add a ZAI key'))
        .catch(error => {
            console.warn('Context warmup failed:', error);
            setAgentStatus('Context partial');
        });
    document.getElementById('api-key-input')?.addEventListener('keydown', event => {
        if (event.key === 'Enter') {
            event.preventDefault();
            saveApiKey();
            document.getElementById('chat-input')?.focus();
        }
    });
    document.getElementById('book-select')?.addEventListener('change', () => {
        updateChatContext();
        renderCurrentChatHistory();
    });

    // Fix chart sizing after a short delay
    setTimeout(() => {
        Object.values(state.charts).forEach(chart => {
            if (chart) chart.resize();
        });
    }, 100);

    // Auto-refresh every hour
    setInterval(refreshAllData, CONFIG.refreshInterval);

    console.log('Astro Trading Dashboard ready');
});

