    document.querySelector('.sidebar').classList.toggle('open');
    document.querySelector('.chat-panel').classList.remove('open');
}

function toggleChat() {
    document.querySelector('.chat-panel').classList.toggle('open');
    document.querySelector('.sidebar').classList.remove('open');
}

/* ========== VARIABLES ========== */
:root {
    --bg-primary: #08090c;
    --bg-secondary: #0f1014;
    --bg-card: #16171c;
    --bg-hover: #1e1f26;
    --border-color: #26272e;
    --text-primary: #f0f0f2;
    --text-secondary: #9ca3af;
    --text-dim: #6b7280;
    --gold: #fbbf24;
    --gold-dim: rgba(251, 191, 36, 0.15);
    --silver: #94a3b8;
    --silver-dim: rgba(148, 163, 184, 0.15);
    --copper: #d97706;
    --copper-dim: rgba(217, 119, 6, 0.15);
    --bitcoin: #f7931a;
    --bitcoin-dim: rgba(247, 147, 26, 0.15);
    --bullish: #10b981;
    --danger: #ef4444;
    --warning: #f59e0b;
    --sidebar-w: 220px;
    --chat-w: 460px;
}

/* ========== RESET ========== */
*, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }
html { font-size: 15px; }
body {
    font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    background: var(--bg-primary);
    color: var(--text-primary);
    line-height: 1.5;
    min-height: 100vh;
}

