    height: 36px;
    background: linear-gradient(135deg, var(--gold), var(--copper));
    border-radius: 8px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 700;
    font-size: 0.85rem;
    color: #000;
}

.title {
